  "updatedAt": "2026-05-23T00:00:00.000Z",
  "product": {
    "name": "Orbit",
    "category": "GitHub-native agent infrastructure",
    "problem": "AI agents can write code, but most projects still lack a durable operating layer for identity, permissions, memory, receipts, budget, lifecycle, and human approval.",
    "solution": "Orbit turns a repository into an agent control plane: the repo stores the agent passport, capability registry, command surface, memory, proof receipts, lifecycle state, and policy gates.",
    "positioning": "Security checks are guardrails. The product is the infrastructure that lets an autonomous software operator run, prove work, and stay governable."
  },
  "activePhase": {
    "id": "foundation-control-plane",
    "name": "Foundation Control Plane",
    "status": "active",
    "goal": "Make Orbit understandable as infrastructure before expanding execution power."
  },
  "layers": [
    {
      "id": "github-intake",
      "name": "GitHub Intake",
      "status": "active",
      "description": "Issues and comments are the public command and approval intake for Orbit."
    },
    {
      "id": "repo-memory",
      "name": "Repo Memory",
      "status": "active",
      "description": "Memory files hold identity, tasks, knowledge, roadmap, opportunities, and durable state."
    },
    {
      "id": "agent-lifecycle",
      "name": "Agent Lifecycle",
      "status": "active",
      "description": "GitHub Actions and deterministic fallback keep Orbit waking, working, and sleeping in cycles."
    },
    {
      "id": "permissions",
      "name": "Permissions And Approvals",
      "status": "active",
      "description": "Owner approval gates protect spend, signing, token actions, and risky external movement."
    },
    {
      "id": "proof-receipts",
      "name": "Proof Receipts",
      "status": "active",
      "description": "Cycle notes and runtime proofs record what Orbit saw, did, refused, and learned."
    },
    {
      "id": "wallet-policy",
      "name": "Wallet Policy",
      "status": "active",
      "description": "Read-only wallet state exposes approval labels, revenue cadence, and blocked live actions."
    },
    {
      "id": "sdk-cli-access",
      "name": "SDK And CLI Access",
      "status": "planned",
      "description": "Local read-only entry points for other repos, agents, and dashboards come last."
    }
  ],
  "surfaces": [
    {
      "id": "repo-control-plane",
      "name": "Repository Control Plane",
      "status": "active",
      "path": "memory/",
      "description": "Machine-readable state for identity, roadmap, tasks, treasury policy, opportunities, infrastructure, and durable knowledge."
    },
    {
      "id": "lifecycle-runtime",
      "name": "Lifecycle Runtime",
      "status": "active",
      "path": ".github/workflows/",
      "description": "Scheduled and event-driven wake cycles with deterministic fallback, budget gates, proofs, and optional commits."
    },
    {
      "id": "capability-registry",
      "name": "Capability Registry",
      "status": "active",
      "path": "src/agent/tools.js",
      "description": "A declared tool surface with schemas, permission boundaries, and blocked actions."
    },
    {
      "id": "command-router",
      "name": "Issue Command Router",
      "status": "active",
      "path": "src/agent/github.js",
      "description": "GitHub issues and comments act as the public command and approval interface."
    },
    {
      "id": "receipt-ledger",
      "name": "Receipt Ledger",
      "status": "active",
      "path": "runtime/proofs/",
      "description": "Every cycle writes reviewable proof records with actions, file changes, route privacy, and result summaries."
    },
    {
      "id": "agent-passport",
      "name": "Agent Passport",
      "status": "planned",
      "path": "memory/infrastructure.json",
      "description": "Portable identity bundle for mission, permissions, capability claims, proof roots, and revocation status."
    },
    {
      "id": "sdk-cli",
      "name": "SDK And CLI Surface",
      "status": "planned",
      "path": "src/cli/",
      "description": "Local commands and future client helpers for reading Orbit status, receipts, capabilities, and installation checks."
    },
    {
      "id": "integration-adapters",
      "name": "Integration Adapters",
      "status": "research",
      "path": "src/agent/",
      "description": "Replaceable adapters for GitHub, model providers, search, treasury observation, and future external protocols."
    }
  ],
  "capabilities": [
    {
      "id": "identity",
      "name": "Identity And Mission",
      "status": "active",
      "mode": "repo_public",
      "evidence": [
        "memory/identity.md",
        "README.md"
      ]
    },
    {
      "id": "lifecycle",
      "name": "Wake/Sleep Lifecycle",
      "status": "active",
      "mode": "github_actions",
